    resource.write(ABILITY_DAMAGE_BONUS, getDamageBonus(), out);

    // Write the ability damage type
    resource.write(ABILITY_DAMAGE_TYPE, TYPE_ARRAY[getDamageType()], out);

    // Write the ability number of effects
    resource.write(ABILITY_NUM_EFFECTS, getNumberOfEffects(), out);

